/// Spec function: the hash state after hashing a MontgomeryPoint
/// This is defined as the hash state of its canonical byte representation
pub open spec fn spec_state_after_hash_montgomery<H>(
    initial_state: H,
    point: &MontgomeryPoint,
) -> H {
    // The hash state of a MontgomeryPoint is determined by its canonical bytes
    // Canonical bytes are: spec_fe51_as_bytes(spec_fe51_from_bytes(point.0))
    let canonical_seq = spec_fe51_as_bytes(&spec_fe51_from_bytes(&point.0));
    let canonical_bytes = seq_to_array_32(canonical_seq);
    spec_state_after_hash(initial_state, &canonical_bytes)
}

/// Spec function: Extended Euclidean Algorithm
///
/// Computes (gcd, x, y) such that gcd(a, b) = a*x + b*y (Bezout's identity)
///
/// This is a constructive algorithm that produces the Bezout coefficients.
/// Base case: gcd(a, 0) = a = a*1 + 0*0, so (a, 1, 0)
/// Recursive case: if gcd(b, a%b) = b*x' + (a%b)*y' = b*x' + (a - b*(a/b))*y'
///                                = a*y' + b*(x' - (a/b)*y')
///                 so (gcd, y', x' - (a/b)*y')
pub open spec fn spec_extended_gcd(a: nat, b: nat) -> ExtGcdResult
    decreases b,
{
    if b == 0 {
        ExtGcdResult { gcd: a, x: 1, y: 0 }
    } else {
        let r = spec_extended_gcd(b, a % b);
        ExtGcdResult { gcd: r.gcd, x: r.y, y: r.x - (a / b) as int * r.y }
    }
}

/// Spec function: Greatest Common Divisor using Euclidean algorithm
///
/// This is a constructive definition that computes gcd(a, b) recursively.
/// The algorithm is: gcd(a, 0) = a; gcd(a, b) = gcd(b, a % b) for b > 0
pub open spec fn spec_gcd(a: nat, b: nat) -> nat
    decreases b,
{
    if b == 0 {
        a
    } else {
        spec_gcd(b, a % b)
    }
}

/// Spec function: Compute modular inverse using extended Euclidean algorithm
///
/// For a and m coprime (gcd(a, m) = 1), returns the unique x in [0, m) such that
/// a * x ≡ 1 (mod m).
///
/// The inverse is computed from Bezout's identity: a*x + m*y = 1
/// Taking mod m: (a*x) % m = 1
///
/// We normalize the result to be in [0, m) by computing x % m (handling negative x).
pub open spec fn spec_mod_inverse(a: nat, m: nat) -> nat
    recommends
        m > 1,
        spec_gcd(a % m, m) == 1,
{
    if m <= 1 || spec_gcd(a % m, m) != 1 {
        0  // Undefined case - return 0 by convention

    } else {
        let r = spec_extended_gcd(a % m, m);
        // r.x might be negative, so normalize to [0, m)
        (((r.x % (m as int)) + (m as int)) % (m as int)) as nat
    }
}

pub open spec fn add(a: nat, b: nat) -> nat {
    a + b
}

/// Bundled validity predicate for the n-tuple of (scalar_digits, NielsPoint)
/// pairs that Pippenger operates on.  For each index k ∈ [0, n):
///
///  - digits are valid radix-2^w with dc digits
///  - the ProjectiveNielsPoint is valid and 54-bounded in all limbs
///  - its affine projection matches pts_affine[k]
///  - pts_affine[k] is canonical (< p)
///  - digits_seqs[k] = scalars_points[k].0.view()
pub open spec fn pippenger_input_valid(
    scalars_points: Seq<([i8; 64], ProjectiveNielsPoint)>,
    pts_affine: Seq<(nat, nat)>,
    digits_seqs: Seq<Seq<i8>>,
    w: nat,
    dc: nat,
) -> bool {
    let n = pts_affine.len() as int;
    &&& scalars_points.len() as int == n
    &&& digits_seqs.len() as int == n
    // Digit validity
    &&& forall|k: int|
        0 <= k < n ==> is_valid_radix_2w(
            &(#[trigger] scalars_points[k]).0,
            w,
            dc,
        )
    // Niels point validity + 54-bounded limbs
    &&& forall|k: int|
        0 <= k < n ==> is_valid_projective_niels_point((#[trigger] scalars_points[k]).1)
    &&& forall|k: int|
        0 <= k < n ==> fe51_limbs_bounded(&(#[trigger] scalars_points[k]).1.Y_plus_X, 54)
    &&& forall|k: int|
        0 <= k < n ==> fe51_limbs_bounded(&(#[trigger] scalars_points[k]).1.Y_minus_X, 54)
    &&& forall|k: int| 0 <= k < n ==> fe51_limbs_bounded(&(#[trigger] scalars_points[k]).1.Z, 54)
    &&& forall|k: int|
        0 <= k < n ==> fe51_limbs_bounded(
            &(#[trigger] scalars_points[k]).1.T2d,
            54,
        )
    // Affine correspondence: niels affine == pts_affine
    &&& forall|k: int|
        0 <= k < n ==> projective_niels_point_as_affine_edwards((#[trigger] scalars_points[k]).1)
            == pts_affine[k]
    // pts_affine are canonical
    &&& forall|k: int|
        0 <= k < n ==> (#[trigger] pts_affine[k]).0 < p() && pts_affine[k].1
            < p()
    // digits_seqs connection
    &&& forall|k: int| 0 <= k < n ==> (#[trigger] digits_seqs[k]) == scalars_points[k].0@
}

/// Number of digit columns, derived from the window width w.
pub open spec fn sp_digit_count(w: nat) -> nat {
    if w < 8 {
        ((256 + w as int - 1) / w as int) as nat
    } else {
        ((256 + w as int - 1) / w as int + 1) as nat
    }
}

/// Digit sequences for each scalar, derived from the [i8; 64] arrays.
pub open spec fn sp_digits_seqs(sp: Seq<([i8; 64], ProjectiveNielsPoint)>) -> Seq<Seq<i8>> {
    Seq::new(sp.len(), |i: int| sp[i].0@)
}

/// Affine (x, y) coordinates of each point, derived from the ProjectiveNielsPoint.
pub open spec fn sp_points_affine(sp: Seq<([i8; 64], ProjectiveNielsPoint)>) -> Seq<(nat, nat)> {
    Seq::new(sp.len(), |i: int| projective_niels_point_as_affine_edwards(sp[i].1))
}

/// Column sum: col(j, n) = sum_{k=0}^{n-1} [d_{k,j}] * P_k
///
/// Recursive over k (number of points summed).
/// Base case: col(j, 0) = O  (identity).
/// Step:      col(j, k+1) = col(j, k) + [d_{k,j}] * P_k
///
/// Shared by both CT (radix-16 digits) and VT (NAF digits).
pub open spec fn straus_column_sum(
    points_affine: Seq<(nat, nat)>,
    digits: Seq<Seq<i8>>,
    j: int,
    n: int,
) -> (nat, nat)
    decreases n,
{
    if n <= 0 {
        edwards_identity()
    } else {
        let prev = straus_column_sum(points_affine, digits, j, n - 1);
        let term = edwards_scalar_mul_signed(points_affine[n - 1], digits[n - 1][j] as int);
        edwards_add(prev.0, prev.1, term.0, term.1)
    }
}

/// Convert a boolean array (bits in little-endian order) to a natural number.
/// bits[0] is the least significant bit.
/// Computes: sum_{i=0}^{255} bits[i] * 2^i
pub open spec fn bits_as_nat(bits: [bool; 256]) -> nat {
    bits_as_nat_rec(bits, 0)
}

/// Recursive helper for bits_as_nat.
pub open spec fn bits_as_nat_rec(bits: [bool; 256], index: int) -> nat
    decreases 256 - index,
{
    if index >= 256 {
        0
    } else {
        let bit_value = if bits[index] {
            1nat
        } else {
            0nat
        };
        bit_value * pow2(index as nat) + bits_as_nat_rec(bits, index + 1)
    }
}

/// Convert a boolean slice (bits in big-endian order) to a natural number.
/// bits[0] is the most significant bit.
/// Used for scalar multiplication where bits are processed MSB first.
pub open spec fn bits_be_as_nat(bits: &[bool], len: int) -> nat
    recommends
        0 <= len <= bits.len(),
    decreases len,
{
    if len <= 0 {
        0
    } else {
        let bit_value = if bits[len - 1] {
            1nat
        } else {
            0nat
        };
        bit_value + 2 * bits_be_as_nat(bits, len - 1)
    }
}

/// Little-endian natural value of first j bytes of a sequence.
/// Computes: bytes[0] + bytes[1]*2^8 + ... + bytes[j-1]*2^((j-1)*8)
///
/// This is the canonical "prefix sum" for byte-to-nat conversion proofs.
/// Used for incremental byte-to-word conversion and injectivity proofs.
pub open spec fn bytes_as_nat_prefix(bytes: Seq<u8>, j: nat) -> nat
    recommends
        j <= bytes.len(),
    decreases j,
{
    if j == 0 {
        0
    } else {
        let j1: nat = (j - 1) as nat;
        bytes_as_nat_prefix(bytes, j1) + pow2(((j1) * 8) as nat) * bytes[j1 as int] as nat
    }
}

/// Little-endian natural value of an arbitrary-length byte sequence.
/// Computes: bytes[0] + bytes[1] * 2^8 + bytes[2] * 2^16 + ...
pub open spec fn bytes_seq_as_nat(bytes: Seq<u8>) -> nat
    decreases bytes.len(),
{
    if bytes.len() == 0 {
        0
    } else {
        (bytes[0] as nat) + pow2(8) * bytes_seq_as_nat(bytes.skip(1))
    }
}

/// Load 8 consecutive bytes from a byte array and interpret as a little-endian u64.
///
/// Returns: bytes[i] + bytes[i+1] * 2^8 + ... + bytes[i+7] * 2^56
///
/// This is commonly used when unpacking byte arrays into larger word-sized limbs.
#[verusfmt::skip]
pub open spec fn spec_load8_at(input: &[u8], i: usize) -> nat {
    (pow2(0 * 8) * input[i + 0] +
     pow2(1 * 8) * input[i + 1] +
     pow2(2 * 8) * input[i + 2] +
     pow2(3 * 8) * input[i + 3] +
     pow2(4 * 8) * input[i + 4] +
     pow2(5 * 8) * input[i + 5] +
     pow2(6 * 8) * input[i + 6] +
     pow2(7 * 8) * input[i + 7]) as nat
}

/// Check if an AffineNielsPoint corresponds to an EdwardsPoint
/// An AffineNielsPoint (y_plus_x, y_minus_x, xy2d) corresponds to EdwardsPoint (X:Y:Z:T) if:
/// 1. y_plus_x = y + x (mod p) where x = X/Z, y = Y/Z (affine coordinates)
/// 2. y_minus_x = y - x (mod p)
/// 3. xy2d = x * y * 2d (mod p)
pub open spec fn affine_niels_corresponds_to_edwards(
    niels: AffineNielsPoint,
    point: EdwardsPoint,
) -> bool {
    let (x_proj, y_proj, z_proj, _t) = edwards_point_as_nat(point);
    let d = fe51_as_canonical_nat(&EDWARDS_D);

    let z_inv = field_inv(z_proj);
    let x = field_mul(x_proj, z_inv);
    let y = field_mul(y_proj, z_inv);

    let y_plus_x_niels = fe51_as_canonical_nat(&niels.y_plus_x);
    let y_minus_x_niels = fe51_as_canonical_nat(&niels.y_minus_x);
    let xy2d_niels = fe51_as_canonical_nat(&niels.xy2d);

    &&& y_plus_x_niels == field_add(y, x)
    &&& y_minus_x_niels == field_sub(y, x)
    &&& xy2d_niels == field_mul(field_mul(field_mul(x, y), 2), d)
}

/// Extract affine coordinates (x, y) from an AffineNielsPoint
/// Given: y_plus_x = y + x and y_minus_x = y - x
/// Solve for: x = (y_plus_x - y_minus_x) / 2, y = (y_plus_x + y_minus_x) / 2
pub open spec fn affine_niels_point_as_affine_edwards(niels: AffineNielsPoint) -> (nat, nat) {
    let y_plus_x = fe51_as_canonical_nat(&niels.y_plus_x);
    let y_minus_x = fe51_as_canonical_nat(&niels.y_minus_x);

    let x = field_mul(field_sub(y_plus_x, y_minus_x), field_inv(2));
    let y = field_mul(field_add(y_plus_x, y_minus_x), field_inv(2));

    (x, y)
}

