}

/// Sign bit of the X coordinate (LSB of the canonical value).
pub open spec fn edwards_x_sign_bit(point: crate::edwards::EdwardsPoint) -> u8 {
    fe51_as_canonical_nat_sign_bit(&edwards_x(point))
}

