spec_functions.body:
/// Check if a CompletedPoint is valid
/// A CompletedPoint ((X:Z), (Y:T)) in P¹ × P¹ is valid if:
/// 1. The affine point (X/Z, Y/T) lies on the Edwards curve
/// 2. Z ≠ 0 and T ≠ 0
pub open spec fn is_valid_completed_point(
    point: crate::backend::serial::curve_models::CompletedPoint,
) -> bool {
    let (x_abs, y_abs, z_abs, t_abs) = completed_point_as_nat(point);

    // Z and T must be non-zero
    z_abs != 0 && t_abs != 0
        &&
    // The affine coordinates (X/Z, Y/T) must be on the curve
    is_on_edwards_curve(field_mul(x_abs, field_inv(z_abs)), field_mul(y_abs, field_inv(t_abs)))
}

/// Spec: A valid EdwardsBasepointTable for a basepoint B contains 32 LookupTables where:
/// - table.0[i] contains [1·(16²)^i·B, 2·(16²)^i·B, ..., 8·(16²)^i·B]
/// - All entries have bounded limbs (< 2^54)
///
/// This enables computing [scalar] * B via radix-16 representation of scalar.
#[cfg(feature = "precomputed-tables")]
pub open spec fn is_valid_edwards_basepoint_table(
    table: EdwardsBasepointTable,
    basepoint: (nat, nat),
) -> bool {
    // Each of the 32 LookupTables contains correct multiples of (16²)^i * B
    // and has bounded limbs and valid entries
    forall|i: int|
        #![trigger table.0[i]]
        0 <= i < 32 ==> {
            &&& crate::specs::window_specs::is_valid_lookup_table_affine_coords(
                table.0[i].0,
                edwards_scalar_mul(basepoint, pow256(i as nat)),
                8,
            )
            &&& crate::specs::window_specs::lookup_table_affine_limbs_bounded(table.0[i].0)
            &&& forall|j: int|
                0 <= j < 8 ==> is_valid_affine_niels_point(#[trigger] table.0[i].0[j])
        }
}

/// Check if an EdwardsPoint in extended coordinates is valid
/// An EdwardsPoint (X:Y:Z:T) is valid if:
/// 1. Z ≠ 0
/// 2. The projective curve equation holds: (Y² - X²)·Z² = Z⁴ + d·X²·Y²
/// 3. The Segre relation holds: X·Y = Z·T
///
/// Extended coordinates (X:Y:Z:T) with X·Y = Z·T enable faster point arithmetic.
/// Reference: [HWCD2008] Section 3 for extended twisted Edwards coordinates
pub open spec fn is_valid_edwards_point(point: crate::edwards::EdwardsPoint) -> bool {
    let x = fe51_as_canonical_nat(&edwards_x(point));
    let y = fe51_as_canonical_nat(&edwards_y(point));
    let z = fe51_as_canonical_nat(&edwards_z(point));
    let t = fe51_as_canonical_nat(&edwards_t(point));

    is_valid_extended_edwards_point(x, y, z, t)
}

/// Spec function: Check if a y-coordinate corresponds to a valid point on the curve.
/// Mirrors the sqrt_ratio_i computation from field.rs to determine if u/v is a square.
/// From the curve equation: x² = (y² - 1) / (d·y² + 1)
/// This computes the same check as sqrt_ratio_i(&u, &v) where:
///   u = y² - 1
///   v = d·y² + 1
/// Returns true if u/v is a square (i.e., x can be recovered)
pub open spec fn is_valid_edwards_y_coordinate(y: nat) -> bool {
    let d = fe51_as_canonical_nat(&EDWARDS_D);
    let y2 = field_square(y);

    // Compute u = y² - 1
    let u = field_sub(y2, 1);

    // Compute v = d·y² + 1
    let v = field_add(field_mul(d, y2), 1);

    if u % p() == 0 {
        // If u = 0, then y² = 1, so y = ±1, which gives valid points (x=0, y=±1)
        true
    } else if v % p() == 0 {
        // If v = 0 but u ≠ 0, division by zero case - invalid
        false
    } else {
        // Check if there exists r such that r² * v ≡ ±u (mod p)
        // This is what sqrt_ratio_i determines
        exists|r: nat|
            r < p() && (#[trigger] field_mul(field_square(r), v) == u % p() || #[trigger] field_mul(
                field_square(r),
                v,
            ) == field_neg(u))
    }
}

/// Math-level validity predicate for an Edwards point in **extended coordinates** (X:Y:Z:T).
///
/// This is the "unpacked" version of `is_valid_edwards_point` that operates directly on the
/// mathematical values `(x, y, z, t)` (all reduced mod p via `field_*`).
///
/// An (X:Y:Z:T) tuple is valid iff:
/// 1. Z ≠ 0 (mod p)
/// 2. The projective curve equation holds: (Y² - X²)·Z² = Z⁴ + d·X²·Y²
/// 3. The Segre relation holds: X·Y = Z·T
pub open spec fn is_valid_extended_edwards_point(x: nat, y: nat, z: nat, t: nat) -> bool {
    field_canonical(z) != 0 && is_on_edwards_curve_projective(x, y, z) && field_mul(x, y)
        == field_mul(z, t)
}

/// Check if a ProjectiveNielsPoint is valid
/// A valid ProjectiveNielsPoint must correspond to some valid, limb-bounded EdwardsPoint.
/// The limb-bounded condition is needed because `choose` witnesses are spec-mode
/// (no type invariant access), so limb bounds must be carried explicitly.
pub open spec fn is_valid_projective_niels_point(niels: ProjectiveNielsPoint) -> bool {
    exists|point: EdwardsPoint|
        is_valid_edwards_point(point) && edwards_point_limbs_bounded(point)
            && #[trigger] projective_niels_corresponds_to_edwards(niels, point)
}

/// Check if a ProjectivePoint is valid
/// A ProjectivePoint (X:Y:Z) in P² is valid if:
/// 1. Z ≠ 0
/// 2. The projective curve equation holds: (Y² - X²)·Z² = Z⁴ + d·X²·Y²
///
/// This is equivalent to the affine point (X/Z, Y/Z) lying on the Edwards curve.
pub open spec fn is_valid_projective_point(point: ProjectivePoint) -> bool {
    let (x, y, z) = projective_point_edwards_as_nat(point);

    // Z must be non-zero and projective curve equation must hold
    z != 0 && is_on_edwards_curve_projective(x, y, z)
}

/// A well-formed EdwardsPoint: mathematically valid and properly bounded.
pub open spec fn is_well_formed_edwards_point(point: crate::edwards::EdwardsPoint) -> bool {
    is_valid_edwards_point(point) && edwards_point_limbs_bounded(point) && sum_of_limbs_bounded(
        &edwards_y(point),
        &edwards_x(point),
        u64::MAX,
    )
}

/// Spec for Montgomery-to-Edwards conversion with sign bit selection.
///
/// Converts Montgomery u-coordinate to Edwards affine (x, y) via:
/// 1. Birational map: y = (u-1)/(u+1)
/// 2. Decompression: recover x from y with given sign_bit
///
/// **Sign normalisation when y² = 1:** In this case x = 0, so x is even and
/// the only valid sign is 0. The exec code (`to_edwards` in montgomery.rs)
/// naturally produces sign 0 because negating 0 is a no-op. We mirror that
/// here by forcing `effective_sign = 0`.
///
/// Returns identity (0, 1) on failure (u = -1 or invalid y).
pub open spec fn montgomery_to_edwards_affine(u: nat, sign_bit: u8) -> (nat, nat) {
    if u == field_sub(0, 1) {
        // u = -1: birational map has zero denominator
        edwards_identity()
    } else {
        let y = edwards_y_from_montgomery_u(u);
        // y² = 1 ⟹ x = 0 ⟹ sign must be 0 (see doc comment above).
        let effective_sign = if field_square(y) == 1 {
            0u8
        } else {
            sign_bit
        };
        match edwards_decompress_from_y_and_sign(y, effective_sign) {
            Some(P) => P,
            None => edwards_identity(),
        }
    }
}

/// Negation of an AffineNielsPoint as structure
pub open spec fn negate_affine_niels(p: AffineNielsPoint) -> AffineNielsPoint {
    AffineNielsPoint {
        y_plus_x: p.y_minus_x,
        y_minus_x: p.y_plus_x,
        xy2d: crate::field::FieldElement {
            limbs: crate::specs::field_specs_u64::spec_negate(p.xy2d.limbs),
        },
    }
}

/// Negation of a ProjectiveNielsPoint as structure
pub open spec fn negate_projective_niels(p: ProjectiveNielsPoint) -> ProjectiveNielsPoint {
    ProjectiveNielsPoint {
        Y_plus_X: p.Y_minus_X,
        Y_minus_X: p.Y_plus_X,
        Z: p.Z,
        T2d: crate::field::FieldElement {
            limbs: crate::specs::field_specs_u64::spec_negate(p.T2d.limbs),
        },
    }
}

/// Compute 256^n (i.e., (16²)^n) for basepoint table indexing
/// Uses pow2(8*n) since 256 = 2^8
pub open spec fn pow256(n: nat) -> nat {
    pow2(8 * n)
}

/// Check if a ProjectiveNielsPoint corresponds to an EdwardsPoint
/// A ProjectiveNielsPoint (Y_plus_X, Y_minus_X, Z, T2d) corresponds to EdwardsPoint (X:Y:Z:T) if:
/// 1. Y_plus_X = Y + X (mod p)
/// 2. Y_minus_X = Y - X (mod p)
/// 3. Z matches
/// 4. T2d = 2d * T (mod p) where T = XY/Z
pub open spec fn projective_niels_corresponds_to_edwards(
    niels: ProjectiveNielsPoint,
    point: EdwardsPoint,
) -> bool {
    let (x, y, z, t) = edwards_point_as_nat(point);
    let d = fe51_as_canonical_nat(&EDWARDS_D);

    let y_plus_x = fe51_as_canonical_nat(&niels.Y_plus_X);
    let y_minus_x = fe51_as_canonical_nat(&niels.Y_minus_X);
    let niels_z = fe51_as_canonical_nat(&niels.Z);
    let t2d = fe51_as_canonical_nat(&niels.T2d);

    &&& y_plus_x == field_add(y, x)
    &&& y_minus_x == field_sub(y, x)
    &&& niels_z == z
    &&& t2d == field_mul(field_mul(2, d), t)
}

/// Extract affine coordinates (x, y) from a ProjectiveNielsPoint
/// Given: Y_plus_X = Y + X, Y_minus_X = Y - X, and Z (all in projective coords)
/// First recover projective X and Y, then convert to affine: x = X/Z, y = Y/Z
pub open spec fn projective_niels_point_as_affine_edwards(niels: ProjectiveNielsPoint) -> (
    nat,
    nat,
) {
    let y_plus_x = fe51_as_canonical_nat(&niels.Y_plus_X);
    let y_minus_x = fe51_as_canonical_nat(&niels.Y_minus_X);
    let z = fe51_as_canonical_nat(&niels.Z);

    // Recover projective X and Y from Y+X and Y-X
    let x_proj = field_mul(field_sub(y_plus_x, y_minus_x), field_inv(2));
    let y_proj = field_mul(field_add(y_plus_x, y_minus_x), field_inv(2));

    // Convert to affine by dividing by Z
    let z_inv = field_inv(z);
    let x = field_mul(x_proj, z_inv);
    let y = field_mul(y_proj, z_inv);

    (x, y)
}

/// Returns the abstract affine coordinates (x, y) from an Edwards ProjectivePoint.
/// An Edwards ProjectivePoint (X:Y:Z) represents affine point (X/Z, Y/Z).
pub open spec fn projective_point_as_affine_edwards(point: ProjectivePoint) -> (nat, nat) {
    let (x, y, z) = projective_point_edwards_as_nat(point);
    let z_inv = field_inv(z);
    (field_mul(x, z_inv), field_mul(y, z_inv))
}

/// Returns the field element values (X, Y, Z) from an Edwards ProjectivePoint.
/// An Edwards ProjectivePoint (X:Y:Z) is in projective coordinates.
pub open spec fn projective_point_edwards_as_nat(point: ProjectivePoint) -> (nat, nat, nat) {
    let x = fe51_as_canonical_nat(&point.X);
    let y = fe51_as_canonical_nat(&point.Y);
    let z = fe51_as_canonical_nat(&point.Z);
    (x, y, z)
}

/// Spec for ProjectivePoint::as_extended conversion
/// Converts from P² to P³ via:
///   (X:Y:Z) ↦ (X·Z : Y·Z : Z² : X·Y)
/// This preserves the affine point and establishes the extended coordinate invariant
pub open spec fn projective_to_extended(point: ProjectivePoint) -> (nat, nat, nat, nat) {
    let (x, y, z) = projective_point_edwards_as_nat(point);
    (field_mul(x, z), field_mul(y, z), field_square(z), field_mul(x, y))
}

/// The Ed25519 basepoint B in affine coordinates (x, y).
/// This is the generator point of the prime-order subgroup.
///
/// References the actual constant ED25519_BASEPOINT_POINT from constants.rs.
/// The y-coordinate is 4/5 mod p (the first 255 bits of the compressed form).
/// The x-coordinate is the positive square root satisfying the curve equation.
///
/// Reference: [RFC8032] Section 5.1
pub closed spec fn spec_ed25519_basepoint() -> (nat, nat) {
    (
        u64_5_as_nat(
            [
                1738742601995546u64,
                1146398526822698u64,
                2070867633025821u64,
                562264141797630u64,
                587772402128613u64,
            ],
        ),
        u64_5_as_nat(
            [
                1801439850948184u64,
                1351079888211148u64,
                450359962737049u64,
                900719925474099u64,
                1801439850948198u64,
            ],
        ),
    )
}

/// Top-level spec for `EdwardsPoint::nonspec_map_to_curve_verus`.
///
/// Reference: RFC 9380 Section 6.7.1 - Elligator 2 Method
/// <https://www.rfc-editor.org/rfc/rfc9380.html#section-6.7.1>
///
/// Note from Dalek code: This is NOT a proper hash-to-curve (non-uniform distribution).
/// A proper hash-to-curve applies Elligator twice and adds the results.
pub open spec fn spec_nonspec_map_to_curve(hash_bytes: Seq<u8>) -> (nat, nat)
    recommends
        hash_bytes.len() == 32,
{
    // Extract sign bit from bit 255 (MSB of last byte)
    let sign_bit: u8 = (hash_bytes[31] & 0x80u8) >> 7;
    // Interpret bytes as field element (mod 2^255 to clear high bit, then reduce mod p)
    let fe_nat = (bytes_seq_as_nat(hash_bytes) % pow2(255)) % p();
    // Elligator2 encoding: field element -> Montgomery u-coordinate
    let u = spec_elligator_encode(fe_nat);
    // Convert Montgomery to Edwards with sign bit selecting x
    let P = montgomery_to_edwards_affine(u, sign_bit);
    // Cofactor clearing: multiply by 8 to ensure prime-order subgroup
    edwards_scalar_mul(P, 8)
}

/// Spec function to compute sum of all EdwardsPoints in a sequence.
/// Returns the affine coordinates of the result.
/// Note: Processes from back to front to match iterative loop order.
pub open spec fn sum_of_points(points: Seq<EdwardsPoint>) -> (nat, nat)
    decreases points.len(),
{
    if points.len() == 0 {
        // Identity point in affine coordinates: (0, 1)
        (0, 1)
    } else {
        let last = (points.len() - 1) as int;
        let prev = sum_of_points(points.subrange(0, last));
        let point_affine = edwards_point_as_affine(points[last]);
        edwards_add(prev.0, prev.1, point_affine.0, point_affine.1)
    }
}

/// Spec function to compute sum of scalar multiplications.
/// Returns the affine coordinates of sum(scalars[i] * points[i] for i in 0..min(len_s, len_p)).
pub open spec fn sum_of_scalar_muls(scalars: Seq<Scalar>, points: Seq<EdwardsPoint>) -> (nat, nat)
    decreases scalars.len(),
{
    let len = if scalars.len() <= points.len() {
        scalars.len()
    } else {
        points.len()
    };
    if len == 0 {
        // Identity point in affine coordinates: (0, 1)
        (0, 1)
    } else {
        let last = (len - 1) as int;
        let prev = sum_of_scalar_muls(scalars.subrange(0, last), points.subrange(0, last));
        let point_affine = edwards_point_as_affine(points[last]);
        // Use scalar_as_nat (not spec_scalar) to match implementation ensures clauses
        let scalar_nat = scalar_as_nat(&scalars[last]);
        let scaled = edwards_scalar_mul(point_affine, scalar_nat);
        edwards_add(prev.0, prev.1, scaled.0, scaled.1)
    }
}

/// Returns the canonical mathematical value of a field element in [0, p)
/// where p = 2^255 - 19
pub open spec fn fe51_as_canonical_nat(fe: &FieldElement51) -> nat {
    u64_5_as_field_canonical(fe.limbs)
}

/// Spec function: Get the sign bit of a field element
/// In Curve25519, the sign bit is the least significant bit of the canonical representation
pub open spec fn fe51_as_canonical_nat_sign_bit(fe: &FieldElement51) -> u8 {
    ((fe51_as_canonical_nat(fe)) % 2) as u8
}

pub open spec fn fe51_as_nat(fe: &FieldElement51) -> nat {
    u64_5_as_nat(fe.limbs)
}

/// Spec function: b^2 * v = u (mod p)
pub open spec fn fe51_is_sqrt_ratio(
    u: &FieldElement51,
    v: &FieldElement51,
    r: &FieldElement51,
) -> bool {
    is_sqrt_ratio(fe51_as_canonical_nat(u), fe51_as_canonical_nat(v), fe51_as_canonical_nat(r))
}

/// Spec function: r^2 * v = i*u (mod p), where i = sqrt(-1)
/// Used for the nonsquare case in sqrt_ratio_i
pub open spec fn fe51_is_sqrt_ratio_times_i(
    u: &FieldElement51,
    v: &FieldElement51,
    r: &FieldElement51,
) -> bool {
    is_sqrt_ratio_times_i(
        fe51_as_canonical_nat(u),
        fe51_as_canonical_nat(v),
        fe51_as_canonical_nat(r),
    )
}

/// Spec predicate: all limbs are bounded by a given bit limit
pub open spec fn fe51_limbs_bounded(fe: &FieldElement51, bit_limit: u64) -> bool {
    u64_5_bounded(fe.limbs, bit_limit)
}

/// Canonical non-negative representative ("absolute value" in GF(p)):
/// negate if the canonical encoding is odd, else identity.
pub open spec fn field_abs(a: nat) -> nat {
    if is_negative(a) {
        field_neg(a)
    } else {
        a
    }
}

/// Math-level field addition
pub open spec fn field_add(a: nat, b: nat) -> nat {
    field_canonical(a + b)
}

/// Returns the canonical mathematical value when creating a field element from bytes.
/// The bytes are interpreted as a little-endian integer with the high bit of byte[31] ignored.
/// The result is the canonical value in [0, p) where p = 2^255 - 19.
pub open spec fn field_element_from_bytes(bytes: &[u8; 32]) -> nat {
    field_canonical(u8_32_as_nat(bytes) % pow2(255))
}

/// Math-level field inversion: returns w such that (a * w) % p == 1
///
/// For non-zero elements (a % p() != 0), this returns the unique multiplicative
/// inverse modulo p. By convention, when a % p() == 0, this returns 0.
///
/// The existence of inverses for non-zero elements is guaranteed by field_inv_property,
/// which relies on p being prime.
pub open spec fn field_inv(a: nat) -> nat {
    if a % p() == 0 {
        0  // Convention: inverse of 0 is defined as 0

    } else {
        spec_mod_inverse(a, p())
    }
}

/// Math-level field multiplication
pub open spec fn field_mul(a: nat, b: nat) -> nat {
    field_canonical(a * b)
}

/// Math-level field negation
pub open spec fn field_neg(a: nat) -> nat {
    field_canonical((p() - field_canonical(a)) as nat)
}

/// Compute a square root modulo p (if it exists)
/// Returns some y such that y^2 ≡ a (mod p)
/// The result is unspecified if a is not a quadratic residue
/// Note result is not unique
pub open spec fn field_sqrt(a: nat) -> nat
    recommends
        is_square(a),
{
    choose|y: nat| y < p() && #[trigger] field_mul(y, y) == field_canonical(a)
}

/// Math-level field squaring
pub open spec fn field_square(a: nat) -> nat {
    field_canonical(a * a)
}

/// Math-level field subtraction
pub open spec fn field_sub(a: nat, b: nat) -> nat {
    field_canonical((field_canonical(a) + p() - field_canonical(b)) as nat)
}

/// Spec function: two field elements are inverses if their product is 1 (mod p)
pub open spec fn is_inverse_field(a: &FieldElement51, b: &FieldElement51) -> bool {
    field_mul(fe51_as_canonical_nat(a), fe51_as_canonical_nat(b)) == 1
}

/// Spec predicate: a field element is negative if its canonical low bit is 1.
pub open spec fn is_negative(a: nat) -> bool {
    field_canonical(a) % 2 == 1
}

/// Spec function: r² * v = u (mod p) — math version operating on nat values
/// This is the mathematical equivalent of fe51_is_sqrt_ratio but without FieldElement wrappers.
/// Use this when working with mathematical values directly in lemmas.
pub open spec fn is_sqrt_ratio(u: nat, v: nat, r: nat) -> bool {
    field_canonical(r * r * v) == field_canonical(u)
}

/// Spec function: r² * v = i*u (mod p) — math version operating on nat values
/// Used for the nonsquare case in sqrt_ratio_i.
/// This is the mathematical equivalent of fe51_is_sqrt_ratio_times_i.
pub open spec fn is_sqrt_ratio_times_i(u: nat, v: nat, r: nat) -> bool {
    field_canonical(r * r * v) == field_mul(sqrt_m1(), u)
}

/// Check if a value is a quadratic residue (square) modulo p
pub open spec fn is_square(a: nat) -> bool {
    exists|y: nat| (#[trigger] field_mul(y, y)) == field_canonical(a)
}

/// Inverse square root in GF(p): returns the canonical nonneg r such that
/// r²·a ≡ 1 or r²·a ≡ √(-1) (mod p).
///
/// Mirrors the sqrt_ratio_i(1, a) computation:
///   a3  = a² · a
///   a7  = a3² · a
///   r   = a3 · (a7)^((p-5)/8)          candidate
///   check = a · r²                      verify: should be in {1, -1, i, -i}
///   if check ∈ {-1, -i}: r = r · i      adjust for flipped cases
///   if is_negative(r): r = -r            canonical sign (even parity)
pub open spec fn nat_invsqrt(a: nat) -> nat {
    if a % p() == 0 {
        0
    } else {
        let a3 = field_mul(field_square(a), a);
        let a7 = field_mul(field_square(a3), a);
        let k = ((p() - 5) / 8) as nat;
        let r_raw = field_mul(a3, (pow(a7 as int, k) as nat) % p());
        let check = field_mul(a, field_square(r_raw));
        let neg_one = field_neg(1);
        let neg_i = field_neg(sqrt_m1());
        let r_adj = if check == neg_one || check == neg_i {
            field_mul(sqrt_m1(), r_raw)
        } else {
            r_raw
        };
        if is_negative(r_adj) {
            field_neg(r_adj)
        } else {
            r_adj
        }
    }
}

/// Spec function: result of limb-wise addition (what add_spec returns)
pub open spec fn spec_add_fe51_limbs(a: &FieldElement51, b: &FieldElement51) -> FieldElement51 {
    FieldElement51 {
        limbs: [
            (a.limbs[0] + b.limbs[0]) as u64,
            (a.limbs[1] + b.limbs[1]) as u64,
            (a.limbs[2] + b.limbs[2]) as u64,
            (a.limbs[3] + b.limbs[3]) as u64,
            (a.limbs[4] + b.limbs[4]) as u64,
        ],
    }
}

pub open spec fn spec_fe51_as_bytes(fe: &FieldElement51) -> Seq<u8> {
    // Step 1: Basic reduction to ensure h < 2*p
    let limbs = spec_reduce(fe.limbs);

    // Step 2: Compute q (quotient) to detect if limbs >= p
    // q = 0 if h < p, q = 1 if h >= p
    // This works because h >= p <==> h + 19 >= 2^255
    let q0 = ((limbs[0] + 19) as u64) >> 51;
    let q1 = ((limbs[1] + q0) as u64) >> 51;
    let q2 = ((limbs[2] + q1) as u64) >> 51;
    let q3 = ((limbs[3] + q2) as u64) >> 51;
    let q = ((limbs[4] + q3) as u64) >> 51;

    // Step 3: Compute r = h - pq = h + 19q - 2^255q
    // Add 19*q to limbs[0]
    let limbs0_adj = (limbs[0] + 19 * q) as u64;

    // Step 4: Propagate carries and mask to 51 bits (this subtracts 2^255q implicitly)
    let limbs1_adj = (limbs[1] + (limbs0_adj >> 51)) as u64;
    let limbs0_canon = (limbs0_adj & mask51) as u64;
    let limbs2_adj = (limbs[2] + (limbs1_adj >> 51)) as u64;
    let limbs1_canon = (limbs1_adj & mask51) as u64;
    let limbs3_adj = (limbs[3] + (limbs2_adj >> 51)) as u64;
    let limbs2_canon = (limbs2_adj & mask51) as u64;
    let limbs4_adj = (limbs[4] + (limbs3_adj >> 51)) as u64;
    let limbs3_canon = (limbs3_adj & mask51) as u64;
    // Discard carry from limbs[4], which subtracts 2^255q
    let limbs4_canon = (limbs4_adj & mask51) as u64;

    // Step 5: Pack canonical limbs into 32 bytes (little-endian)
    seq![
        limbs0_canon as u8,
        (limbs0_canon >> 8) as u8,
        (limbs0_canon >> 16) as u8,
        (limbs0_canon >> 24) as u8,
        (limbs0_canon >> 32) as u8,
        (limbs0_canon >> 40) as u8,
        ((limbs0_canon >> 48) | (limbs1_canon << 3)) as u8,
        (limbs1_canon >> 5) as u8,
        (limbs1_canon >> 13) as u8,
        (limbs1_canon >> 21) as u8,
        (limbs1_canon >> 29) as u8,
        (limbs1_canon >> 37) as u8,
        ((limbs1_canon >> 45) | (limbs2_canon << 6)) as u8,
        (limbs2_canon >> 2) as u8,
        (limbs2_canon >> 10) as u8,
        (limbs2_canon >> 18) as u8,
        (limbs2_canon >> 26) as u8,
        (limbs2_canon >> 34) as u8,
        (limbs2_canon >> 42) as u8,
        ((limbs2_canon >> 50) | (limbs3_canon << 1)) as u8,
        (limbs3_canon >> 7) as u8,
        (limbs3_canon >> 15) as u8,
        (limbs3_canon >> 23) as u8,
        (limbs3_canon >> 31) as u8,
        (limbs3_canon >> 39) as u8,
        ((limbs3_canon >> 47) | (limbs4_canon << 4)) as u8,
        (limbs4_canon >> 4) as u8,
        (limbs4_canon >> 12) as u8,
        (limbs4_canon >> 20) as u8,
        (limbs4_canon >> 28) as u8,
        (limbs4_canon >> 36) as u8,
        (limbs4_canon >> 44) as u8,
    ]
}

/// Spec function for FieldElement::from_bytes
/// Takes a 32-byte array and produces a FieldElement51
/// The high bit of byte[31] is ignored, giving a 255-bit value
pub open spec fn spec_fe51_from_bytes(bytes: &[u8; 32]) -> FieldElement51 {
    // Mimic the implementation in field.rs:from_bytes
    // Load 8-byte chunks at specified offsets and mask to 51-bit limbs
    let low_51_bit_mask = mask51;

    FieldElement51 {
        limbs: [
        // load bits [  0, 64), mask to 51 bits

            (spec_load8_at(bytes, 0) as u64) & low_51_bit_mask,
            // load bits [ 48,112), shift right by 3, mask to 51 bits
            ((spec_load8_at(bytes, 6) as u64) >> 3) & low_51_bit_mask,
            // load bits [ 96,160), shift right by 6, mask to 51 bits
            ((spec_load8_at(bytes, 12) as u64) >> 6) & low_51_bit_mask,
            // load bits [152,216), shift right by 1, mask to 51 bits
            ((spec_load8_at(bytes, 19) as u64) >> 1) & low_51_bit_mask,
            // load bits [192,256), shift right by 12, mask to 51 bits (this ignores high bit)
            ((spec_load8_at(bytes, 24) as u64) >> 12) & low_51_bit_mask,
        ],
    }
}

/// Spec function: result of limb-wise subtraction with reduction (what sub_spec returns)
/// Adds multiples of p to avoid underflow, then reduces
pub open spec fn spec_sub_limbs(a: &FieldElement51, b: &FieldElement51) -> FieldElement51 {
    FieldElement51 {
        limbs: spec_reduce(
            [
                ((a.limbs[0] + 36028797018963664u64) - b.limbs[0]) as u64,
                ((a.limbs[1] + 36028797018963952u64) - b.limbs[1]) as u64,
                ((a.limbs[2] + 36028797018963952u64) - b.limbs[2]) as u64,
                ((a.limbs[3] + 36028797018963952u64) - b.limbs[3]) as u64,
                ((a.limbs[4] + 36028797018963952u64) - b.limbs[4]) as u64,
            ],
        ),
    }
}

/// The mathematical value of SQRT_M1 (sqrt(-1) mod p)
/// This is the 4th root of unity i such that i² = -1 (mod p)
pub open spec fn sqrt_m1() -> nat {
    fe51_as_canonical_nat(&constants::SQRT_M1)
}

/// Spec predicate: sum of limbs are bounded by a given bit limit
pub open spec fn sum_of_limbs_bounded(
    fe1: &FieldElement51,
    fe2: &FieldElement51,
    bound: u64,
) -> bool {
    forall|i: int| 0 <= i < 5 ==> fe1.limbs[i] + fe2.limbs[i] < bound
}

/// Spec predicate: all limbs are bounded by a given bit limit
pub open spec fn u64_5_bounded(limbs: [u64; 5], bit_limit: u64) -> bool {
    forall|i: int| 0 <= i < 5 ==> #[trigger] limbs[i] < (1u64 << bit_limit)
}

/// Canonical little-endian bytes for a nat (mod 2^256).
pub open spec fn u8_32_from_nat(n: nat) -> [u8; 32] {
    choose|b: [u8; 32]| u8_32_as_nat(&b) == n % pow2(256)
}

pub open spec fn field_canonical(n: nat) -> nat {
    n % p()
}

pub open spec fn p() -> nat {
    (pow2(255) - 19) as nat
}

pub open spec fn pre_reduce_limbs(limbs: [u64; 5]) -> [u64; 5] {
    let r = [
        (sixteen_p_vec[0] - limbs[0]) as u64,
        (sixteen_p_vec[1] - limbs[1]) as u64,
        (sixteen_p_vec[2] - limbs[2]) as u64,
        (sixteen_p_vec[3] - limbs[3]) as u64,
        (sixteen_p_vec[4] - limbs[4]) as u64,
    ];
    r
}

pub open spec fn spec_negate(limbs: [u64; 5]) -> [u64; 5] {
    let r = spec_reduce(pre_reduce_limbs(limbs));
    r
}

pub open spec fn spec_reduce(limbs: [u64; 5]) -> (r: [u64; 5]) {
    let r = [
        ((limbs[0] & mask51) + (limbs[4] >> 51) * 19) as u64,
        ((limbs[1] & mask51) + (limbs[0] >> 51)) as u64,
        ((limbs[2] & mask51) + (limbs[1] >> 51)) as u64,
        ((limbs[3] & mask51) + (limbs[2] >> 51)) as u64,
        ((limbs[4] & mask51) + (limbs[3] >> 51)) as u64,
    ];
    r
}

pub open spec fn u64_5_as_field_canonical(limbs: [u64; 5]) -> nat {
    field_canonical(u64_5_as_nat(limbs))
}

/// Check if all optional points in a sequence are Some.
pub open spec fn all_points_some(points: Seq<Option<EdwardsPoint>>) -> bool {
    forall|i: int| 0 <= i < points.len() ==> points[i].is_some()
}

/// Spec function to convert an iterator of RistrettoPoints directly to
/// a sequence of EdwardsPoints (extracting .0 from each).
pub uninterp spec fn spec_edwards_from_ristretto_iter<P, J>(iter: J) -> Seq<EdwardsPoint>;

