/// Spec function to convert an iterator of Option<RistrettoPoint> directly to
/// a sequence of Option<EdwardsPoint> (extracting .0 from each Some).
pub uninterp spec fn spec_optional_edwards_from_ristretto_iter<J>(iter: J) -> Seq<
    Option<EdwardsPoint>,
>;

/// Spec function to compute sum of all RistrettoPoints in a sequence.
/// Returns the affine coordinates of the result.
pub open spec fn sum_of_ristretto_points(points: Seq<RistrettoPoint>) -> (nat, nat)
    decreases points.len(),
{
    if points.len() == 0 {
        // Identity point in affine coordinates: (0, 1)
        (0, 1)
    } else {
        let last = (points.len() - 1) as int;
        let prev = sum_of_ristretto_points(points.subrange(0, last));
        let point_affine = edwards_point_as_affine(points[last].0);
        edwards_add(prev.0, prev.1, point_affine.0, point_affine.1)
    }
}

/// Extract EdwardsPoints from an Option sequence (assumes all are Some).
pub open spec fn unwrap_points(points: Seq<Option<EdwardsPoint>>) -> Seq<EdwardsPoint>
    recommends
        all_points_some(points),
{
    points.map(|_i, opt: Option<EdwardsPoint>| opt.unwrap())
}

/// True iff `encode(data)` equals some element of `coset`.
///
/// `data`: 16-byte message.  `coset`: the 4 affine points `{P, P+T₂, P+T₄, P+T₆}`.
pub open spec fn is_lizard_preimage_coset(data: Seq<u8>, coset: [(nat, nat); 4]) -> bool
    recommends
        data.len() == 16,
{
    let enc = spec_lizard_encode(data);
    enc == coset[0] || enc == coset[1] || enc == coset[2] || enc == coset[3]
}

/// Map from Jacobi quartic point `(S, T)` to affine Edwards coordinates `(x, y)`.
///
/// The Jacobi quartic associated to `−x² + y² = 1 + d·x²·y²` (with `a = −1`) is
/// `T² = S⁴ + 2(a − 2d)·S² + 1`.
///
/// ```text
///   y = (1 − S²) / (1 + S²)
///   x = −2·S / (T · √(ad − 1))
/// ```
///
/// where `√(ad − 1) = √(−d − 1)` is `spec_sqrt_ad_minus_one()`.
///
/// Derivation: from `to_jacobi_quartic_ristretto`, `S = γ·Y²·(Z−Y)·X` and
/// `T = (−2/√(a−d))·Z·γ·Y²·(Z−Y)`, so `S/T = −√(a−d)·x/2`, giving
/// `x = −2·S/(T·√(ad−1))`.  The `y` formula follows from `S² = (Z−Y)/(Z+Y)`.
///
/// Requires `1 + S² ≠ 0` and `T · √(ad−1) ≠ 0` (division denominators).
///
/// Used in:
/// - `to_jacobi_quartic_ristretto` ensures (coset correctness)
/// - `elligator_inv` ensures (round-trip with `spec_elligator_ristretto_flavor`)
pub open spec fn jacobi_to_edwards_affine(s: nat, t: nat) -> (nat, nat)
    recommends
        field_add(1, field_square(s)) != 0,
        field_mul(t, spec_sqrt_ad_minus_one()) != 0,
{
    // y = (1 − S²) / (1 + S²)
    let s_sq = field_square(s);
    let y = field_mul(field_sub(1, s_sq), field_inv(field_add(1, s_sq)));
    // x = −2S / (T · √(ad−1))
    let sqrt_ad_m1 = spec_sqrt_ad_minus_one();
    let x = field_mul(field_neg(field_mul(2, s)), field_inv(field_mul(t, sqrt_ad_m1)));
    (x, y)
}

/// Construct the 32-byte string `b(m)` used by Lizard before interpreting it as
/// a field element.
///
/// ```text
/// m ──► [b(m)] ──► r(m) ──► P(m)
///        ^^^^
/// ```
///
/// 1. `SHA256(m)` — pseudorandom padding
/// 2. Overwrite bytes 8..24 with `m` — recoverable payload
/// 3. `b[0] &= 254` — ensure positive (Elligator maps ±r identically)
/// 4. `b[31] &= 63` — canonical range (< 2²⁵⁴)
pub open spec fn lizard_fe_bytes(data: Seq<u8>) -> [u8; 32]
    recommends
        data.len() == 16,
{
    let digest = spec_sha256(data);
    let s = Seq::new(
        32,
        |i: int|
            if 8 <= i < 24 {
                data[i - 8]
            } else {
                digest[i]
            },
    );
    let s = s.update(0, s[0] & 254u8);
    let s = s.update(31, s[31] & 63u8);
    seq_to_array_32(s)
}

/// Field element `r(m) ∈ F_p` — deterministic Elligator input derived from `b(m)`.
///
/// ```text
/// m ──► b(m) ──► [r(m)] ──► P(m)
///                 ^^^^
/// ```
pub open spec fn lizard_r(fe_bytes: &[u8; 32]) -> nat {
    fe51_as_canonical_nat(&spec_fe51_from_bytes(fe_bytes))
}

/// ∃! m ∈ {0,1}¹²⁸ such that `encode(m) ∈ coset(x, y)`.
///
/// `(x, y)`: affine Edwards coordinates of any coset representative.
/// Returns `true` iff exactly one such `m` exists.
pub open spec fn lizard_ristretto_has_unique_preimage(x: nat, y: nat) -> bool {
    let coset = ristretto_coset_affine(x, y);
    exists|data: Seq<u8>|
        data.len() == 16 && #[trigger] is_lizard_preimage_coset(data, coset) && forall|
            data2: Seq<u8>,
        |
            data2.len() == 16 && #[trigger] is_lizard_preimage_coset(data2, coset) ==> data2 == data
}

/// Return the unique preimage over `coset(x, y)`, or `None`.
///
/// `(x, y)`: affine Edwards coordinates.  Returns `Some(m)` with `|m| == 16`.
/// Top-level spec for `lizard_decode_verus`.
pub closed spec fn spec_lizard_decode_ristretto(x: nat, y: nat) -> Option<Seq<u8>> {
    let coset = ristretto_coset_affine(x, y);
    if lizard_ristretto_has_unique_preimage(x, y) {
        Some(
            choose|data: Seq<u8>|
                data.len() == 16 && #[trigger] is_lizard_preimage_coset(data, coset),
        )
    } else {
        None
    }
}

/// Point `P(m) = Elligator(r(m))` — the Lizard encoding.
///
/// ```text
/// m ──► b(m) ──► r(m) ──► [P(m)]
///                          ^^^^^
/// ```
///
/// The message rides inside the Elligator preimage at bytes 8..24.
/// Returns `(x, y) ∈ F_p × F_p`.  Top-level spec for `lizard_encode_verus`.
pub open spec fn spec_lizard_encode(data: Seq<u8>) -> (nat, nat)
    recommends
        data.len() == 16,
{
    spec_elligator_ristretto_flavor(lizard_r(&lizard_fe_bytes(data)))
}

/// The Montgomery reduction property: result * R ≡ input (mod L)
pub open spec fn montgomery_congruent(result: &Scalar52, limbs: &[u128; 9]) -> bool {
    (scalar52_as_nat(result) * montgomery_radix()) % group_order() == slice128_as_nat(limbs)
        % group_order()
}

/// The value bound that montgomery_reduce requires to produce a canonical output.
/// When the total value is < R * L, the intermediate result_raw will be < 2L,
/// which allows sub(result_raw, L) to produce a canonical result.
///
/// # Motivation
/// - result_raw = (input + N*L) / R, where N < R
/// - For result_raw < 2L: we need input/R + L < 2L, i.e., input < R*L
///
/// # Relationship to r4_safe_bound
/// - canonical_bound (T < R×L ≈ 2^512) implies r4_safe_bound (T < 2^520)
/// - canonical_bound additionally ensures result < L (canonical)
///
/// # Note
/// This is purely a VALUE constraint. The per-limb overflow bounds
/// (montgomery_reduce_input_bounds) must be established separately.
pub open spec fn montgomery_reduce_canonical_bound(limbs: &[u128; 9]) -> bool {
    slice128_as_nat(limbs) < montgomery_radix() * group_order()
}

/// The limb bounds that montgomery_reduce requires to avoid overflow.
/// These are the bounds produced by mul_internal(bounded, bounded).
///
/// # Motivation
/// montgomery_reduce performs iterative computations where each iteration
/// accumulates products of limbs. To avoid overflow in u128 arithmetic,
/// we need these specific bounds on each input limb.
#[verusfmt::skip]
pub open spec fn montgomery_reduce_input_bounds(limbs: &[u128; 9]) -> bool {
    limbs[0] < pow2(104) &&  // 1 product term
    limbs[1] < pow2(105) &&  // 2 product terms
    limbs[2] < pow2(106) &&  // 3 product terms
    limbs[3] < pow2(107) &&  // 4 product terms
    limbs[4] < pow2(107) &&  // 5 product terms
    limbs[5] < pow2(107) &&  // 4 product terms
    limbs[6] < pow2(106) &&  // 3 product terms
    limbs[7] < pow2(105) &&  // 2 product terms
    limbs[8] < pow2(104)     // 1 product term
}

/// Given u-coordinate of a Montgomery point (non-torsion),
/// return the unique affine Montgomery point (u, v)
/// where v is the canonical square root of u*(u^2 + A*u + 1).
pub open spec fn canonical_montgomery_lift(u: nat) -> MontgomeryAffine
    recommends
        is_valid_u_coordinate(u),
{
    let v = canonical_sqrt(montgomery_rhs(u));
    MontgomeryAffine::Finite { u: u % p(), v }
}

