spec_functions.body:
/// Choose a canonical square root.
/// Return the sqrt(r) whose least-significant bit is 0.
/// (This matches Ed25519’s canonical-sign rule.)
pub open spec fn canonical_sqrt(r: nat) -> nat
    recommends
        is_square(r),
{
    let s1 = field_sqrt(r);  // some square root
    let s2 = field_neg(s1);  // the other root

    if (s1 % 2 == 0) {
        s1
    } else {
        s2
    }
}

/// Map Montgomery u to Edwards affine y via y = (u-1)/(u+1).
/// Recommends u != -1 to avoid division by zero.
pub open spec fn edwards_y_from_montgomery_u(u: nat) -> nat
    recommends
        u != field_sub(0, 1),
{
    let denom = field_add(u, 1);
    let numerator = field_sub(u, 1);
    field_mul(numerator, field_inv(denom))
}

/// Check if a Montgomery u-coordinate is invalid for conversion to Edwards
/// u = -1 is invalid because it corresponds to a point on the twist
pub open spec fn is_equal_to_minus_one(u: nat) -> bool {
    u == field_sub(0, 1)  // u == -1

}

/// Check if a MontgomeryPoint's u-coordinate corresponds to a valid point on the Montgomery curve.
///
/// A MontgomeryPoint is valid if its u-coordinate allows a canonical Montgomery lift,
/// which requires that montgomery_rhs(u) = u³ + A·u² + u is a quadratic residue (square) mod p.
/// This ensures there exists a v such that v² = montgomery_rhs(u), making (u,v) a point on the curve.
pub open spec fn is_valid_montgomery_point(point: crate::montgomery::MontgomeryPoint) -> bool {
    let u = montgomery_point_as_nat(point);
    is_valid_u_coordinate(u)
}

pub open spec fn is_valid_u_coordinate(u: nat) -> bool {
    is_square(montgomery_rhs(u))
}

/// Addition on the Montgomery curve using the chord-tangent method.
/// For the Montgomery curve B·v² = u³ + A·u² + u (with B=1, A=486662):
///
/// Addition formulas:
/// - If P = ∞ or Q = ∞: return the other point (identity element)
/// - If P = -Q (same u, opposite v): return ∞
/// - If P = Q (point doubling): λ = (3u₁² + 2Au₁ + 1) / (2v₁)
/// - Otherwise (distinct points): λ = (v₂ - v₁) / (u₂ - u₁)
///
/// Then: u₃ = λ² - A - u₁ - u₂  and  v₃ = λ(u₁ - u₃) - v₁
pub open spec fn montgomery_add(P: MontgomeryAffine, Q: MontgomeryAffine) -> MontgomeryAffine {
    match (P, Q) {
        (MontgomeryAffine::Infinity, _) => Q,
        (_, MontgomeryAffine::Infinity) => P,
        (MontgomeryAffine::Finite { u: u1, v: v1 }, MontgomeryAffine::Finite { u: u2, v: v2 }) => {
            let A = fe51_as_canonical_nat(&MONTGOMERY_A);

            // P = -Q (same u, opposite v)
            if u1 == u2 && field_add(v1, v2) == 0 {
                MontgomeryAffine::Infinity
            }
            // P = Q (doubling)
             else if u1 == u2 && v1 == v2 {
                let u1_sq = field_square(u1);
                let numerator = field_add(
                    field_add(field_mul(3, u1_sq), field_mul(field_mul(2, A), u1)),
                    1,
                );
                let denominator = field_mul(2, v1);
                let lambda = field_mul(numerator, field_inv(denominator));

                let lambda_sq = field_square(lambda);
                let u3 = field_sub(field_sub(lambda_sq, A), field_mul(2, u1));
                let v3 = field_sub(field_mul(lambda, field_sub(u1, u3)), v1);

                MontgomeryAffine::Finite { u: u3, v: v3 }
            }
            // Add for distinct points P != Q
             else {
                let numerator = field_sub(v2, v1);
                let denominator = field_sub(u2, u1);
                let lambda = field_mul(numerator, field_inv(denominator));

                let lambda_sq = field_square(lambda);
                let u3 = field_sub(field_sub(field_sub(lambda_sq, A), u1), u2);
                let v3 = field_sub(field_mul(lambda, field_sub(u1, u3)), v1);

                MontgomeryAffine::Finite { u: u3, v: v3 }
            }
        },
    }
}

/// Extract u-coordinate from a MontgomeryAffine point
pub open spec fn montgomery_affine_u(P: MontgomeryAffine) -> nat {
    match P {
        MontgomeryAffine::Infinity => 0,  // Convention: infinity maps to 0
        MontgomeryAffine::Finite { u, v: _ } => u,
    }
}

/// Check if a MontgomeryPoint corresponds to an EdwardsPoint
/// via the birational map u = (1+y)/(1-y)
/// Special case: Edwards identity (y=1) maps to u=0
pub open spec fn montgomery_corresponds_to_edwards(
    montgomery: crate::montgomery::MontgomeryPoint,
    edwards: crate::edwards::EdwardsPoint,
) -> bool {
    let u = montgomery_point_as_nat(montgomery);
    let (x, y) = crate::specs::edwards_specs::edwards_point_as_affine(edwards);
    let denominator = field_sub(1, y);

    if denominator == 0 {
        // Special case: Edwards identity (x=0, y=1) maps to Montgomery u=0
        u == 0
    } else {
        // General case: u = (1+y)/(1-y)
        let numerator = field_add(1, y);
        u == field_mul(numerator, field_inv(denominator))
    }
}

/// Returns the u-coordinate of a Montgomery point as a field element
/// Montgomery points only store the u-coordinate; sign information is lost
pub open spec fn montgomery_point_as_nat(point: crate::montgomery::MontgomeryPoint) -> nat {
    field_element_from_bytes(&point.0)
}

/// Compute f(u) = u^3 + A*u^2 + u over the field.
pub open spec fn montgomery_rhs(u: nat) -> nat {
    let A = fe51_as_canonical_nat(&MONTGOMERY_A);
    let u2 = field_mul(u, u);  // u^2
    let u3 = field_mul(u2, u);  // u^3
    let Au2 = field_mul(A, u2);  // A*u^2
    field_add(field_add(u3, Au2), u)  // u^3 + A*u^2 + u

}

/// Scalar multiplication on Montgomery curve (abstract specification)
/// Computes [n]P where n is a scalar and P is a Montgomery point
pub open spec fn montgomery_scalar_mul(P: MontgomeryAffine, n: nat) -> MontgomeryAffine
    decreases n,
{
    if n == 0 {
        MontgomeryAffine::Infinity
    } else {
        montgomery_add(P, montgomery_scalar_mul(P, (n - 1) as nat))
    }
}

/// Scalar multiplication on Montgomery curve, returning only u-coordinate
/// This is what X25519 computes: [n]P returning just the u-coordinate
pub open spec fn montgomery_scalar_mul_u(u: nat, n: nat) -> nat {
    // Compute full scalar mul and extract u-coordinate
    montgomery_affine_u(
        montgomery_scalar_mul(
            MontgomeryAffine::Finite { u, v: canonical_sqrt(montgomery_rhs(u)) },
            n,
        ),
    )
}

/// Check if a Montgomery ProjectivePoint (U:W) represents a MontgomeryAffine point, including ∞.
///
/// We cannot use u-coordinates alone because both ∞ and the finite point (0,0) have u=0.
/// Instead, we distinguish them structurally: ∞ requires W=0 (and U≠0), while finite points
/// require W≠0.
pub open spec fn projective_represents_montgomery_or_infinity(
    P_proj: ProjectivePoint,
    P_aff: MontgomeryAffine,
) -> bool {
    match P_aff {
        MontgomeryAffine::Infinity => {
            // Infinity is represented by W = 0 in projective coordinates.
            // We require U ≠ 0 to exclude the degenerate (0:0), which represents no valid point.
            fe51_as_canonical_nat(&P_proj.W) == 0 && fe51_as_canonical_nat(&P_proj.U) != 0
        },
        MontgomeryAffine::Finite { u, v: _ } => {
            // Same encoding requirement as `projective_represents_montgomery`.
            let W = fe51_as_canonical_nat(&P_proj.W);
            let U = fe51_as_canonical_nat(&P_proj.U);
            W != 0 && U == field_mul(u, W)
        },
    }
}

/// Extract the u-coordinate from a ProjectivePoint (U:W) as u = U/W.
/// Returns 0 if W = 0 (which represents the point at infinity).
pub open spec fn projective_u_coordinate(P: ProjectivePoint) -> nat {
    let U = fe51_as_canonical_nat(&P.U);
    let W = fe51_as_canonical_nat(&P.W);
    if W == 0 {
        0
    } else {
        field_mul(U, field_inv(W))
    }
}

/// Elligator2 mapping from a field element to a Montgomery u-coordinate.
///
/// Given input r, computes:
///   d = -A / (1 + 2*r²)
///   eps = d³ + A*d² + d = d * (d² + A*d + 1)
///   if eps is square: u = d       (point lands on the curve)
///   if eps is not square: u = -d - A  (point lands on the quadratic twist)
///
/// ## Quadratic Twist
///
/// For a Montgomery curve v² = u³ + Au² + u, not every u-coordinate has a
/// corresponding v (i.e., u³ + Au² + u may not be a square). The "quadratic
/// twist" is a related curve containing exactly those points whose u-coordinates
/// are invalid on the original curve.
///
/// - If eps = u³ + Au² + u is a **quadratic residue** (square) → u is on the **curve**
/// - If eps is a **non-residue** (not a square) → u is on the **twist**
///
/// ## Twist Security
///
/// Curve25519 is specifically designed to be "twist-secure". The twist has group
/// order 4 * p' where p' is a large prime, similar to the main curve's order 8 * q.
/// This means:
/// - The Montgomery ladder (used in X25519) produces correct results regardless
///   of whether the input u-coordinate is on the curve or the twist
/// - An attacker cannot learn secret key bits by sending a malicious u-coordinate
///   that corresponds to a point on the twist (a "small subgroup attack")
///
/// The output u is always a valid u-coordinate on either the Montgomery curve
/// or its quadratic twist. This provides a deterministic mapping from field
/// elements to curve points.
pub open spec fn spec_elligator_encode(r: nat) -> nat {
    let A = fe51_as_canonical_nat(&MONTGOMERY_A);
    let r_sq = field_square(r);
    let two_r_sq = field_mul(2, r_sq);
    let d_denom = field_add(1, two_r_sq);  // 1 + 2r²

    // d = -A / (1 + 2r²)
    let d = field_mul(field_neg(A), field_inv(d_denom));

    // eps = d³ + A*d² + d = d * (d² + A*d + 1)
    let d_sq = field_square(d);
    let A_d = field_mul(A, d);
    let inner = field_add(field_add(d_sq, A_d), 1);
    let eps = field_mul(d, inner);

    // Choose u based on whether eps is a quadratic residue
    let eps_is_square = is_square(eps);

    if eps_is_square {
        // eps is square → point is on curve → result u = d
        d
    } else {
        // eps is not square → point is on twist → result u = -d - A
        field_neg(field_add(d, A))
    }
}

/// The X25519/Montgomery basepoint u-coordinate.
///
/// References the actual constant `X25519_BASEPOINT` from `constants.rs`.
/// The u-coordinate is 9, as specified in:
/// - [RFC 7748] Section 4.1: "The u-coordinate of the base point is u = 9"
/// - https://www.rfc-editor.org/rfc/rfc7748#section-4.1
///
/// The Montgomery basepoint corresponds to the Ed25519 basepoint under
/// the birational map between twisted Edwards and Montgomery forms.
///
/// Note: X25519 uses X-only (u-coordinate only) arithmetic, so the full
/// affine point (u, v) is not needed - we only work with u-coordinates.
pub open spec fn spec_x25519_basepoint_u() -> nat {
    field_element_from_bytes(&X25519_BASEPOINT.0)
}

/// Extract the u-coordinate from a MontgomeryAffine point.
/// Maps Infinity to 0, and Finite{u, v} to u.
pub open spec fn u_coordinate(point: MontgomeryAffine) -> nat {
    match point {
        MontgomeryAffine::Infinity => 0,
        MontgomeryAffine::Finite { u, v: _ } => u,
    }
}

/// Uniform distribution predicate for a byte slice.
/// True if the bytes are uniformly distributed over their domain.
pub uninterp spec fn is_uniform_bytes(bytes: &[u8]) -> bool;

/// Uniform distribution predicate for a field element.
/// True if the field element is uniformly distributed over F_p.
pub uninterp spec fn is_uniform_field_element(fe: &FieldElement) -> bool;

/// Uniform distribution predicate for a Ristretto point.
/// True if the point is uniformly distributed over the Ristretto group.
pub uninterp spec fn is_uniform_ristretto_point(point: &RistrettoPoint) -> bool;

/// Uniform distribution predicate for a scalar.
/// True if the scalar is uniformly distributed over [0, l) where l is the group order.
pub uninterp spec fn is_uniform_scalar(scalar: &Scalar) -> bool;

/// Extract the Elligator intermediate values (s, n_t, d_val) from r_0.
/// These are the values computed partway through elligator_ristretto_flavor,
/// before the final completed-point construction.
///
/// Returns (s, n_t, d_val) where:
///   s     = the final s value after conditional assignment
///   n_t   = N_t = c·(r−1)·(d−1)² − D
///   d_val = D = (c₀ − d·r)(r + d)
pub open spec fn elligator_intermediates(r_0: nat) -> (nat, nat, nat) {
    let i = sqrt_m1();
    let d = fe51_as_canonical_nat(&EDWARDS_D);
    let one_minus_d_sq = field_mul(field_sub(1, d), field_add(1, d));
    let d_minus_one_sq = field_square(field_sub(d, 1));
    let c_init: nat = field_neg(1);

    let r = field_mul(i, field_square(r_0));
    let n_s = field_mul(field_add(r, 1), one_minus_d_sq);
    let d_val = field_mul(field_sub(c_init, field_mul(d, r)), field_add(r, d));

    let invsqrt_val = nat_invsqrt(field_mul(n_s, d_val));
    let s_if_square = field_abs(field_mul(invsqrt_val, n_s));
    let was_square = is_sqrt_ratio(n_s, d_val, s_if_square);

    let s_prime_raw = field_mul(s_if_square, r_0);
    let s_prime = if !is_negative(s_prime_raw) {
        field_neg(s_prime_raw)
    } else {
        s_prime_raw
    };

    let s = if was_square {
        s_if_square
    } else {
        s_prime
    };
    let c = if was_square {
        c_init
    } else {
        r
    };
    let n_t = field_sub(field_mul(field_mul(c, field_sub(r, 1)), d_minus_one_sq), d_val);

    (s, n_t, d_val)
}

/// True when the point is the double of some curve point (i.e., lies in 2E).
pub open spec fn is_in_even_subgroup(point: EdwardsPoint) -> bool {
    exists|q: EdwardsPoint|
        edwards_point_as_affine(point) == edwards_scalar_mul(
            #[trigger] edwards_point_as_affine(q),
            2,
        )
}

/// True when the 4 points form a coset base + E[4] (one Ristretto equivalence class).
///
/// E[4] has elements T[0] (identity), T[2], T[4], T[6] from the 8-torsion table.
pub open spec fn is_ristretto_coset(points: [EdwardsPoint; 4], base: EdwardsPoint) -> bool {
    let base_affine = edwards_point_as_affine(base);
    let t2 = edwards_point_as_affine(spec_eight_torsion()[2]);
    let t4 = edwards_point_as_affine(spec_eight_torsion()[4]);
    let t6 = edwards_point_as_affine(spec_eight_torsion()[6]);

    // points[0] = base (T[0] is identity)
    edwards_point_as_affine(points[0])
        == base_affine
    // points[1] = base + T[2]
     && edwards_point_as_affine(points[1]) == edwards_add(
        base_affine.0,
        base_affine.1,
        t2.0,
        t2.1,
    )
    // points[2] = base + T[4]
     && edwards_point_as_affine(points[2]) == edwards_add(
        base_affine.0,
        base_affine.1,
        t4.0,
        t4.1,
    )
    // points[3] = base + T[6]
     && edwards_point_as_affine(points[3]) == edwards_add(base_affine.0, base_affine.1, t6.0, t6.1)
}

/// Ristretto encoding from affine coordinates (x, y).
///
/// Sets Z = 1, T = x·y (the Segre invariant Z·T = X·Y).
///
/// Reference: [RISTRETTO] §5.3
pub open spec fn ristretto_compress_affine(x: nat, y: nat) -> [u8; 32] {
    ristretto_compress_extended(x, y, 1, field_mul(x, y))
}

/// Ristretto encoding from extended coordinates (X : Y : Z : T).
///
/// Given projective coordinates with Z·T = X·Y, computes the canonical
/// 32-byte Ristretto encoding. The algorithm selects the unique representative
/// from the coset P + E[4] whose encoding s satisfies s ≥ 0.
///
/// Reference: [RISTRETTO] §5.3; [DECAF] §6; https://ristretto.group/formulas/encoding.html
pub open spec fn ristretto_compress_extended(x: nat, y: nat, z: nat, t: nat) -> [u8; 32] {
    let u1 = field_mul(field_add(z, y), field_sub(z, y));
    let u2 = field_mul(x, y);
    let invsqrt = nat_invsqrt(field_mul(u1, field_square(u2)));
    let i1 = field_mul(invsqrt, u1);
    let i2 = field_mul(invsqrt, u2);
    let z_inv = field_mul(i1, field_mul(i2, t));
    let den_inv = i2;

    let iX = field_mul(x, sqrt_m1());
    let iY = field_mul(y, sqrt_m1());
    let enchanted_denominator = field_mul(
        i1,
        fe51_as_canonical_nat(&u64_constants::INVSQRT_A_MINUS_D),
    );

    let rotate = is_negative(field_mul(t, z_inv));
    let x_rot = if rotate {
        iY
    } else {
        x
    };
    let y_rot = if rotate {
        iX
    } else {
        y
    };
    let den_inv_rot = if rotate {
        enchanted_denominator
    } else {
        den_inv
    };

    let y_final = if is_negative(field_mul(x_rot, z_inv)) {
        field_neg(y_rot)
    } else {
        y_rot
    };
    let s = field_mul(den_inv_rot, field_sub(z, y_final));
    let s_final = if is_negative(s) {
        field_neg(s)
    } else {
        s
    };

    u8_32_from_nat(s_final)
}

/// The 4 affine points forming the Ristretto coset base + E[4].
///
/// Returns `[base, base+T₂, base+T₄, base+T₆]` as affine `(nat, nat)` tuples.
pub open spec fn ristretto_coset_affine(x: nat, y: nat) -> [(nat, nat); 4] {
    let t2 = edwards_point_as_affine(spec_eight_torsion()[2]);
    let t4 = edwards_point_as_affine(spec_eight_torsion()[4]);
    let t6 = edwards_point_as_affine(spec_eight_torsion()[6]);
    [
        (x, y),
        edwards_add(x, y, t2.0, t2.1),
        edwards_add(x, y, t4.0, t4.1),
        edwards_add(x, y, t6.0, t6.1),
    ]
}

/// Full Ristretto decode for field element s.
/// Returns (x, y, ok) where ok indicates the invsqrt succeeded (square case).
pub open spec fn ristretto_decode_inner(s: nat) -> (nat, nat, bool) {
    let ss = field_square(s);
    let u1 = field_sub(1, ss);
    let u2 = field_add(1, ss);
    let u2_sqr = field_square(u2);
    let neg_d = field_neg(fe51_as_canonical_nat(&EDWARDS_D));
    let u1_sqr = field_square(u1);
    let v = field_sub(field_mul(neg_d, u1_sqr), u2_sqr);

    let v_u2_sqr = field_mul(v, u2_sqr);
    let invsqrt = nat_invsqrt(v_u2_sqr);
    let ok = is_sqrt_ratio(1, v_u2_sqr, invsqrt);

    let dx = field_mul(invsqrt, u2);
    let dy = field_mul(invsqrt, field_mul(dx, v));
    let x_tmp = field_mul(field_add(s, s), dx);
    let x = if is_negative(x_tmp) {
        field_neg(x_tmp)
    } else {
        x_tmp
    };
    let y = field_mul(u1, dy);

    (x, y, ok)
}

/// Whether decoding field element s succeeded (the invsqrt "square" case).
pub open spec fn ristretto_decode_ok(s: nat) -> bool {
    ristretto_decode_inner(s).2
}

/// The x coordinate from decoding field element s.
pub open spec fn ristretto_decode_x(s: nat) -> nat {
    ristretto_decode_inner(s).0
}

/// The y coordinate from decoding field element s.
pub open spec fn ristretto_decode_y(s: nat) -> nat {
    ristretto_decode_inner(s).1
}

/// Two points are Ristretto-equivalent when their difference is a 4-torsion element.
pub open spec fn ristretto_equivalent(p1: EdwardsPoint, p2: EdwardsPoint) -> bool
    recommends
        is_well_formed_edwards_point(p1),
        is_well_formed_edwards_point(p2),
{
    let p1_affine = edwards_point_as_affine(p1);
    let p2_affine = edwards_point_as_affine(p2);
    let diff = edwards_sub(p1_affine.0, p1_affine.1, p2_affine.0, p2_affine.1);

    // The difference must be a 4-torsion element (one of T[0], T[2], T[4], T[6])
    let t0 = edwards_point_as_affine(spec_eight_torsion()[0]);
    let t2 = edwards_point_as_affine(spec_eight_torsion()[2]);
    let t4 = edwards_point_as_affine(spec_eight_torsion()[4]);
    let t6 = edwards_point_as_affine(spec_eight_torsion()[6]);

    diff == t0 || diff == t2 || diff == t4 || diff == t6
}

/// Hash-to-group: constructs a Ristretto point from 64 uniform random bytes.
///
///   b1, b2 = bytes[0..32], bytes[32..64]
///   r1, r2 = from_bytes(b1), from_bytes(b2)
///   result = elligator(r1) + elligator(r2)
///
/// Reference: [RISTRETTO] §4.3.4; https://ristretto.group/formulas/encoding.html
pub open spec fn ristretto_from_uniform_bytes(bytes: &[u8; 64]) -> (nat, nat) {
    let b1 = uniform_bytes_first(bytes);
    let b2 = uniform_bytes_second(bytes);
    let r1 = field_element_from_bytes(&b1);
    let r2 = field_element_from_bytes(&b2);
    let p1 = spec_elligator_ristretto_flavor(r1);
    let p2 = spec_elligator_ristretto_flavor(r2);
    edwards_add(p1.0, p1.1, p2.0, p2.1)
}

/// Elligator map for Ristretto (MAP function): field element r_0 -> affine point (x, y).
///
/// Maps a field element to a Ristretto point deterministically. Computes a
/// completed point from r_0 via sqrt_ratio_i, then converts to affine.
///
/// Given i = sqrt(-1), d = Edwards curve constant, c₀ = -1:
///
///   r   = i · r_0²
///   N_s = (r + 1)(1 - d²)
///   D   = (c₀ - d·r)(r + d)
///   (was_square, s) = sqrt_ratio_i(N_s, D)
///   s'  = -|s · r_0|                      (negate to ensure negative)
///   if !was_square: s = s', c = r          else: s = s, c = c₀
///   N_t = c·(r - 1)·(d - 1)² - D
///
/// Completed point:  X = 2sD,  Y = 1 - s²,  Z = N_t · sqrt(-d - 1),  T = 1 + s²
/// Affine output:    x = X/Z,  y = Y/T
///
/// Reference: [RISTRETTO] §4.3.4; https://ristretto.group/formulas/elligator.html
pub open spec fn spec_elligator_ristretto_flavor(r_0: nat) -> (nat, nat) {
    let (s, n_t, d_val) = elligator_intermediates(r_0);
    let s_sq = field_square(s);

    let sqrt_ad_minus_one = spec_sqrt_ad_minus_one();
    let x_completed = field_mul(field_mul(2, s), d_val);
    let z_completed = field_mul(n_t, sqrt_ad_minus_one);
    let y_completed = field_sub(1, s_sq);
    let t_completed = field_add(1, s_sq);

    let x_affine = field_mul(x_completed, field_inv(z_completed));
    let y_affine = field_mul(y_completed, field_inv(t_completed));

    (x_affine, y_affine)
}

/// Ristretto basepoint = [B] where B is the Ed25519 basepoint.
pub open spec fn spec_ristretto_basepoint() -> (nat, nat) {
    spec_ed25519_basepoint()
}

/// Ristretto encoding from a RistrettoPoint (delegates to extended coordinates).
///
/// Reference: [RISTRETTO] §5.3
pub open spec fn spec_ristretto_compress(point: RistrettoPoint) -> [u8; 32] {
    let (x, y, z, t) = edwards_point_as_nat(point.0);
    ristretto_compress_extended(x, y, z, t)
}

/// Ristretto decompression: bytes -> Option<(x, y, 1, x·y)>.
///
/// Returns None when any of these checks fail:
///   1. s < p  (canonical encoding)
///   2. s mod 2 = 0  (non-negative)
///   3. invsqrt succeeds, t = x·y ≥ 0, and y ≠ 0
///
/// On success, returns extended coordinates (x, y, 1, x·y) where (x, y)
/// are computed by the decode formula (see `ristretto_decode_inner`).
///
/// Reference: [RISTRETTO] §5.2; [DECAF] §6; https://ristretto.group/formulas/decoding.html
pub open spec fn spec_ristretto_decompress(bytes: [u8; 32]) -> Option<(nat, nat, nat, nat)> {
    let s = field_element_from_bytes(&bytes);

    if !(u8_32_as_nat(&bytes) < p()) || is_negative(s) {
        None
    } else {
        let (x, y, ok) = ristretto_decode_inner(s);
        let t = field_mul(x, y);

        if !ok || is_negative(t) || y == 0 {
            None
        } else {
            Some((x, y, 1nat, t))
        }
    }
}

/// The constant sqrt(-d - 1), precomputed for Ristretto's Elligator map.
pub open spec fn spec_sqrt_ad_minus_one() -> nat {
    fe51_as_canonical_nat(&u64_constants::SQRT_AD_MINUS_ONE)
}

/// Spec helper: first 32 bytes of a 64-byte input.
pub open spec fn uniform_bytes_first(bytes: &[u8; 64]) -> [u8; 32] {
    choose|b: [u8; 32]| b@ == bytes@.subrange(0, 32)
}

/// Spec helper: second 32 bytes of a 64-byte input.
pub open spec fn uniform_bytes_second(bytes: &[u8; 64]) -> [u8; 32] {
    choose|b: [u8; 32]| b@ == bytes@.subrange(32, 64)
}

pub open spec fn group_canonical(n: nat) -> nat {
    n % group_order()
}

/// Checks if a Scalar52 is in canonical form:
/// - All limbs are properly bounded (< 2^52)
/// - The value is reduced modulo group order (< L)
///
/// This is the Scalar52 equivalent of is_canonical_scalar for Scalar.
pub open spec fn is_canonical_scalar52(s: &Scalar52) -> bool {
    limbs_bounded(s) && scalar52_as_nat(s) < group_order()
}

pub open spec fn limb_prod_bounded_u128(limbs1: [u64; 5], limbs2: [u64; 5], k: nat) -> bool {
    forall|i: int, j: int| 0 <= i < 5 && 0 <= j < 5 ==> (limbs1[i] * limbs2[j]) * k <= u128::MAX
}

/// Convert a slice of u64 limbs to nat using 52-bit radix.
/// This is for low-level lemmas that work with raw arrays.
pub open spec fn limbs52_as_nat(limbs: &[u64]) -> nat {
    seq_as_nat_52(limbs@.map(|i, x| x as nat))
}

pub open spec fn limbs_bounded(s: &Scalar52) -> bool {
    forall|i: int| 0 <= i < 5 ==> s.limbs[i] < (1u64 << 52)
}

/// Relaxed bound for sub's first argument: limbs 0-3 bounded, limb 4 can exceed 2^52 by up to b[4].
///
/// This is needed for montgomery_reduce where the intermediate result has r4 > 2^52.
/// The sub algorithm still works correctly because:
///   - For limbs 0-3: standard bounded subtraction
///   - For limb 4: a[4] - b[4] < 2^52, so masking doesn't lose bits
///
pub open spec fn limbs_bounded_for_sub(a: &Scalar52, b: &Scalar52) -> bool {
    &&& forall|i: int| 0 <= i < 4 ==> a.limbs[i] < (1u64 << 52)
    &&& a.limbs[4] < (1u64 << 52) + b.limbs[4]
}

pub open spec fn montgomery_radix() -> nat {
    pow2(260)
}

pub open spec fn scalar52_as_canonical_nat(s: &Scalar52) -> nat {
    group_canonical(scalar52_as_nat(s))
}

/// Convert a Scalar52 to its natural number representation.
/// This is the primary spec function for Scalar52 interpretation.
pub open spec fn scalar52_as_nat(s: &Scalar52) -> nat {
    limbs52_as_nat(&s.limbs)
}

/// Convert a sequence of limbs to nat using 52-bit radix (Horner form).
/// This is the base recursive function for Scalar52 limb interpretation.
/// Computes: limbs[0] + limbs[1]*2^52 + limbs[2]*2^104 + ...
pub open spec fn seq_as_nat_52(limbs: Seq<nat>) -> nat
    decreases limbs.len(),
{
    if limbs.len() == 0 {
        0
    } else {
        limbs[0] + seq_as_nat_52(limbs.subrange(1, limbs.len() as int)) * pow2(52)
    }
}

pub open spec fn slice128_as_nat(limbs: &[u128]) -> nat {
    seq_as_nat_52(limbs@.map(|i, x| x as nat))
}

/// Checks if a Scalar satisfies the canonical representation invariants:
/// - Invariant #1: High bit (bit 255) is clear, ensuring s < 2^255
/// - Invariant #2: Scalar is reduced modulo group order, i.e., s < ℓ
pub open spec fn is_canonical_scalar(s: &Scalar) -> bool {
    // Invariant #2: Scalar is reduced (< group order)
    u8_32_as_nat(&s.bytes)
        < group_order()
    // Invariant #1: High bit is clear (< 2^255)
     && s.bytes[31] <= 127
}

/// Returns true iff a byte array represents a clamped integer for X25519.
/// A clamped integer has:
/// - The 3 least significant bits cleared (divisible by 8)
/// - Bit 255 (MSB) cleared (< 2^255), which means bytes[31] <= 127
/// - Bit 254 set (>= 2^254)
/// This creates values in range: 2^254 + 8*{0, 1, 2, ..., 2^251 - 1}
pub open spec fn is_clamped_integer(bytes: &[u8; 32]) -> bool {
    // The 3 least significant bits are cleared (divisible by 8)
    bytes[0] & 0b0000_0111
        == 0
    // Bit 255 (MSB) is cleared, making it < 2^255
     && bytes[31] & 0b1000_0000 == 0
    // Bit 254 is set, so result >= 2^254
     && bytes[31] & 0b0100_0000
        == 0b0100_0000
    // MSB cleared implies bytes[31] <= 127 (needed for mul_req precondition)
     && bytes[31] <= 127
}

/// Returns true iff a and b are multiplicative inverses modulo group_order
/// i.e., a * b ≡ 1 (mod group_order)
pub open spec fn is_inverse(a: &Scalar, b: &Scalar) -> bool {
    group_canonical(scalar_as_nat(a) * scalar_as_nat(b)) == 1
}

/// Returns true iff a scalar is the inverse of a natural number (mod group_order)
pub open spec fn is_inverse_of_nat(s: &Scalar, n: nat) -> bool {
    group_canonical(scalar_as_nat(s) * n) == 1
}

/// Predicate describing a valid width-w Non-Adjacent Form.
pub open spec fn is_valid_naf(naf: Seq<i8>, w: nat) -> bool {
    forall|i: int|
        0 <= i < naf.len() ==> {
            let digit = (#[trigger] naf[i]) as int;
            // Each nonzero digit is odd and within bound
            (digit == 0 || (digit % 2 != 0 && -pow2((w - 1) as nat) < digit && digit < pow2(
                (w - 1) as nat,
            ))) &&
            // At most one nonzero in any w consecutive digits
            forall|j: int|
                1 <= j < w && #[trigger] (i + j) < naf.len() ==> !(digit != 0 && (naf[#[trigger] (i
                    + j)] as int) != 0)
        }
}

/// Predicate describing a valid radix-16 representation with signed digits
/// This is just radix-2^w with w=4
pub open spec fn is_valid_radix_16(digits: &[i8; 64]) -> bool {
    is_valid_radix_2w(digits, 4, 64)
}

/// Predicate describing a valid radix-2^w representation with signed digits.
/// For window size w, coefficients are in [-2^(w-1), 2^(w-1)) for all indices except the last,
/// and [-2^(w-1), 2^(w-1)] for the last index.
///
/// The inclusive bound `<=` for the last digit comes from `as_radix_16` (w=4): its nibble-based
/// algorithm can produce a last digit equal to 8 (= 2^(w-1)). For `as_radix_2w` with w >= 5, the
/// last digit is strictly less than the bound, but the spec stays general so both representations
/// are valid.
pub open spec fn is_valid_radix_2w(digits: &[i8; 64], w: nat, digits_count: nat) -> bool {
    4 <= w <= 8 && digits_count <= 64 && forall|i: int|
        0 <= i < digits_count ==> {
            let bound = pow2((w - 1) as nat) as int;
            if i < digits_count - 1 {
                -bound <= (#[trigger] digits[i]) && (#[trigger] digits[i]) < bound
            } else {
                -bound <= (#[trigger] digits[i]) && (#[trigger] digits[i]) <= bound
            }
        }
}

/// Spec function to compute product of all scalars in a sequence (mod group_order)
/// Returns the natural number representation
/// Note: Processes from back to front to match iterative loop order
pub open spec fn product_of_scalars(scalars: Seq<Scalar>) -> nat
    decreases scalars.len(),
{
    if scalars.len() == 0 {
        1
    } else {
        let last = (scalars.len() - 1) as int;
        group_canonical(
            (product_of_scalars(scalars.subrange(0, last)) * scalar_as_nat(&scalars[last])),
        )
    }
}

/// All radix-16 digits are bounded by [-8, 8]
pub open spec fn radix_16_all_bounded(digits: &[i8; 64]) -> bool {
    forall|i: int| 0 <= i < 64 ==> radix_16_digit_bounded(#[trigger] digits[i])
}

/// Simple bounds check for radix-16 digits: all digits in [-8, 8]
/// This is a simpler predicate than is_valid_radix_16 for easier use
pub open spec fn radix_16_digit_bounded(digit: i8) -> bool {
    -8 <= digit && digit <= 8
}

pub open spec fn reconstruct(naf: Seq<i8>) -> int
    decreases naf.len(),
{
    if naf.len() == 0 {
        0
    } else {
        (naf[0] as int) + 2 * reconstruct(naf.skip(1))
    }
}

/// Reconstructs the integer value from a radix-16 representation
/// This is just radix-2^w with w=4
pub open spec fn reconstruct_radix_16(digits: Seq<i8>) -> int {
    reconstruct_radix_2w(digits, 4)
}

/// Reconstructs an integer from a radix-2^w digit representation
/// The scalar is represented as: a_0 + a_1*2^w + a_2*2^(2w) + ...
pub open spec fn reconstruct_radix_2w(digits: Seq<i8>, w: nat) -> int
    decreases digits.len(),
{
    if digits.len() == 0 {
        0
    } else {
        (digits[0] as int) + pow2(w) * reconstruct_radix_2w(digits.skip(1), w)
    }
}

/// Returns the scalar value reduced modulo group order.
/// This is the value used in scalar multiplication: [n]P where n = scalar_as_canonical(s).
pub open spec fn scalar_as_canonical(s: &Scalar) -> nat {
    u8_32_as_group_canonical(s.bytes)
}

pub open spec fn scalar_as_nat(s: &Scalar) -> nat {
    u8_32_as_nat(&s.bytes)
}

/// Returns true iff a scalar's byte representation equals the given natural number (mod group_order)
pub open spec fn scalar_congruent_nat(s: &Scalar, n: nat) -> bool {
    scalar_as_canonical(s) == group_canonical(n)
}

/// Spec function to compute sum of all scalars in a sequence (mod group_order)
/// Returns the natural number representation
/// Note: Processes from back to front to match iterative loop order
pub open spec fn sum_of_scalars(scalars: Seq<Scalar>) -> nat
    decreases scalars.len(),
{
    if scalars.len() == 0 {
        0
    } else {
        let last = (scalars.len() - 1) as int;
        group_canonical((sum_of_scalars(scalars.subrange(0, last)) + scalar_as_nat(&scalars[last])))
    }
}

pub open spec fn u8_32_as_group_canonical(bytes: [u8; 32]) -> nat {
    group_canonical(u8_32_as_nat(&bytes))
}

/// Spec: Check if a lookup table contains [P, 2P, 3P, ..., size*P] in AffineNiels form
/// Wrapper that takes an EdwardsPoint and extracts affine coords.
pub open spec fn is_valid_lookup_table_affine<const N: usize>(
    table: [AffineNielsPoint; N],
    P: EdwardsPoint,
    size: nat,
) -> bool {
    is_valid_lookup_table_affine_coords(table, edwards_point_as_affine(P), size)
}

/// Spec: Check if a lookup table contains [P, 2P, 3P, ..., size*P] in AffineNiels form
/// where P is given as affine coordinates (nat, nat).
pub open spec fn is_valid_lookup_table_affine_coords<const N: usize>(
    table: [AffineNielsPoint; N],
    basepoint: (nat, nat),
    size: nat,
) -> bool {
    &&& table.len() == size
    &&& forall|j: int|
        #![trigger table[j]]
        0 <= j < size ==> affine_niels_point_as_affine_edwards(table[j]) == edwards_scalar_mul(
            basepoint,
            (j + 1) as nat,
        )
}

/// Spec: Check if a lookup table contains [P, 2P, 3P, ..., size*P] in ProjectiveNiels form
pub open spec fn is_valid_lookup_table_projective<const N: usize>(
    table: [ProjectiveNielsPoint; N],
    P: EdwardsPoint,
    size: nat,
) -> bool {
    &&& table.len() == size
    &&& forall|j: int|
        0 <= j < size ==> projective_niels_point_as_affine_edwards(#[trigger] table[j])
            == edwards_scalar_mul(edwards_point_as_affine(P), (j + 1) as nat)
}

/// Spec: Check if a NafLookupTable5 contains odd multiples [1A, 3A, 5A, 7A, 9A, 11A, 13A, 15A]
/// in AffineNiels form.
pub open spec fn is_valid_naf_lookup_table5_affine(
    table: [AffineNielsPoint; 8],
